    74→  }
    75→
    76→  try {
    77→    // Create agent workspace
    78→    const workspaceDir = join(AGENTS_DIR, agentName);
    79→    const lendingSkillsDir = join(workspaceDir, "skills", "lending");
    80→    const imageGenSkillsDir = join(workspaceDir, "skills", "image-generation");
    81→    mkdirSync(lendingSkillsDir, { recursive: true });
    82→    mkdirSync(imageGenSkillsDir, { recursive: true });
    83→
    84→    // Write OpenClaw config
    85→    const openclawConfig = {
    86→      agents: {
    87→        defaults: { workspace: workspaceDir },
    88→        list: [{ id: agentName, default: true }],
    89→      },
    90→      models: {
    91→        default: "openai/gpt-4o-mini",
    92→      },
    93→    };
    94→
    95→    writeFileSync(
    96→      join(workspaceDir, "openclaw.json"),
    97→      JSON.stringify(openclawConfig, null, 2)
    98→    );
    99→
   100→    // Write lending skill
   101→    const lendingSkill = `---
   102→name: lending
   103→description: >
   104→  Interact with the AgentMicrolending contract on Celo. Request loans, discover
   105→  and fill open loan requests, repay loans, and mark defaults.
   106→version: 2.0.0
   107→---
   108→
   109→# Lending Skill
   110→
   111→You interact with the AgentMicrolending smart contract on Celo for peer-to-peer
   112→lending between autonomous agents. All loans use native CELO.
   113→
   114→## Loan Lifecycle
   115→1. Request: Publish a loan request with amount, repay amount, and deadline
   116→2. Discovery: Scan for open requests via getOpenLoans()
   117→3. Verification: Verify borrower's human-backed status (8004 SBT) on-chain
   118→4. Fund: Send CELO to borrower through fundLoan()
   119→5. Repay: Borrower repays principal + interest via repayLoan() before deadline
   120→6. Default: If deadline passes without repayment, call claimDefaulted()
   121→
   122→## Identity Gate
   123→Before filling a loan, verify the borrower's human wallet holds the 8004
   124→soulbound NFT from Self.xyz at contract 0xaC3DF9ABf80d0F5c020C06B04Cced27763355944.
   125→`;
   126→
   127→    writeFileSync(join(lendingSkillsDir, "SKILL.md"), lendingSkill);
   128→
   129→    // Write image-generation skill
   130→    const imageGenSkill = `---
   131→name: image-generation
   132→description: >
   133→  You are a seller of AI image generation services and a buyer of x402-protected
   134→  services. You operate an HTTP API endpoint that generates images using Google
   135→  Gemini 3.1 Flash Image Preview via OpenRouter. Access is gated by the x402
   136→  payment protocol — clients pay in USDC on Celo per request. You can also
   137→  consume any x402-protected API as a client, paying automatically in USDC.
   138→version: 1.1.0
   139→requires:
   140→  env:
   141→    [
   142→      "X402_SERVICES_URL",
   143→    ]
   144→---
   145→
   146→# Image Generation Service
   147→
   148→You sell AI-generated images through an HTTP API protected by the x402 payment
   149→protocol. Clients pay in USDC on Celo — no API keys, no subscriptions. Payment
   150→happens automatically per-request via signed on-chain authorization.
   151→
   152→## Your Service
   153→
   154→**Endpoint:** \`POST \${process.env.X402_SERVICES_URL || "http://localhost:3002"}/api/image-generation\`
   155→
   156→**Model:** Google Gemini 3.1 Flash Image Preview (via OpenRouter)
   157→
   158→**What it does:** Takes a text prompt and generates a high-quality image,
   159→returned as a base64-encoded PNG inline in the response.
   160→
   161→**Payment chain:** Celo mainnet
   162→**Payment token:** USDC (\`0xcebA9300f2b948710d2653dD7B07f33A8B32118C\`)
   163→
   164→## How x402 Payment Works
   165→
   166→The x402 protocol uses the HTTP 402 Payment Required status code to enable
   167→seamless, per-request payments in USDC on-chain. The same protocol works
   168→whether you are **selling** a service (server side) or **buying** a service
   169→(client side).
   170→
   171→### The x402 Flow
   172→
   173→1. **First request (no payment):** The server responds with HTTP 402 and a
   174→   \`payment-required\` header containing the exact USDC price for that request.
   175→2. **Client signs payment:** The client signs a USDC transfer authorization
   176→   (EIP-712) for the quoted amount.
   177→3. **Retry with payment:** The client resends the same request with a
   178→   \`PAYMENT-SIGNATURE\` header containing the signed authorization.
   179→4. **Server verifies and serves:** The server verifies the payment via the
   180→   facilitator, generates the result, and returns it. The USDC is settled
   181→   on-chain on Celo.
   182→
   183→Clients using \`@x402/fetch\` or \`@x402/axios\` handle this flow automatically —
   184→from their perspective it is a normal API call that costs USDC.
   185→
   186→---
   187→
   188→## Selling: Your Image Generation API
   189→
   190→### Pricing
   191→
   192→The price for each request is calculated dynamically based on the prompt and
   193→expected output.
   194→
   195→#### Rates
   196→
   197→| Component | Rate |
   198→|-----------|------|
   199→| Input (prompt) | $0.50 per million tokens |
   200→| Output (image) | $3.00 per million tokens |
   201→
   202→#### How the price is computed
   203→
   204→1. **Input tokens** are estimated from the prompt text at ~4 characters per
   205→   token: \`input_tokens = ceil(prompt_length / 4)\`
   206→2. **Output tokens** default to 1024 (the typical image generation output).
   207→3. **Total price in USD:**
   208→   \\\`\\\`\\\`
   209→   input_cost  = (input_tokens / 1,000,000) x $0.50
   210→   output_cost = (1,024 / 1,000,000) x $3.00 = $0.003072
   211→   total       = input_cost + output_cost
   212→   \\\`\\\`\\\`
   213→4. The USD amount is converted to USDC atomic units (6 decimals) and included
   214→   in the 402 response.
   215→
   216→#### Price examples
   217→
   218→| Prompt length | Input tokens | Input cost | Output cost | Total USDC |
   219→|---------------|-------------|------------|-------------|------------|
   220→| 50 chars | 13 | $0.000007 | $0.003072 | ~$0.0031 |
   221→| 200 chars | 50 | $0.000025 | $0.003072 | ~$0.0031 |
   222→| 1,000 chars | 250 | $0.000125 | $0.003072 | ~$0.0032 |
   223→| 10,000 chars | 2,500 | $0.001250 | $0.003072 | ~$0.0043 |
   224→
   225→For typical prompts the price is dominated by the output cost (~$0.003), making
   226→it very affordable. Only extremely long prompts shift the price meaningfully.
   227→
   228→### Request Format
   229→
   230→\\\`\\\`\\\`json
   231→{
   232→  "prompt": "A photorealistic orange cat sitting on a windowsill at sunset",
   233→  "image_config": {
   234→    "aspect_ratio": "16:9"
   235→  }
   236→}
   237→\\\`\\\`\\\`
   238→
   239→- **prompt** (required): Text description of the image to generate.
   240→- **image_config** (optional): Configuration like aspect ratio or image size.
   241→
   242→### Response Format
   243→
   244→On successful payment, the response is the full OpenRouter completion object.
   245→The generated image is at \`choices[0].message.images[0].image_url.url\` as a
   246→\`data:image/png;base64,...\` data URI.
   247→
   248→---
   249→
   250→## Buying: Consuming x402-Protected Services
   251→
   252→You are not only a seller — you can also **buy** services from any
   253→x402-protected API. Any HTTP endpoint that returns a 402 Payment Required
   254→response with x402 headers is a service you can pay for and consume
   255→automatically.
   256→
   257→### How to Buy an x402 Service
   258→
   259→Use \`@x402/fetch\` or \`@x402/axios\` with your wallet as the signer. These
   260→libraries intercept the HTTP 402 response, sign the USDC payment authorization
   261→with your private key, and retry the request — all transparently.
   262→
   263→#### Using @x402/fetch
   264→
   265→\\\`\\\`\\\`typescript
   266→import { x402Client, wrapFetchWithPayment } from "@x402/fetch";
   267→import { registerExactEvmScheme } from "@x402/evm/exact/client";
   268→import { privateKeyToAccount } from "viem/accounts";
   269→
   270→const client = new x402Client();
   271→registerExactEvmScheme(client, {
   272→  signer: privateKeyToAccount(process.env.AGENT_PRIVATE_KEY),
   273→});
   274→
   275→const fetchWithPayment = wrapFetchWithPayment(fetch, client);
   276→
   277→const response = await fetchWithPayment("https://some-service.com/api/endpoint", {
   278→  method: "POST",
   279→  headers: { "Content-Type": "application/json" },
   280→  body: JSON.stringify({ prompt: "Hello world" }),
   281→});
   282→
   283→const result = await response.json();
   284→\\\`\\\`\\\`
   285→
   286→#### Using @x402/axios
   287→
   288→\\\`\\\`\\\`typescript
   289→import { x402Client, wrapAxiosWithPayment } from "@x402/axios";
   290→import { registerExactEvmScheme } from "@x402/evm/exact/client";
   291→import { privateKeyToAccount } from "viem/accounts";
   292→import axios from "axios";
   293→
   294→const client = new x402Client();
   295→registerExactEvmScheme(client, {
   296→  signer: privateKeyToAccount(process.env.AGENT_PRIVATE_KEY),
   297→});
   298→
   299→const api = wrapAxiosWithPayment(axios.create(), client);
   300→
   301→const response = await api.post("https://some-service.com/api/endpoint", {
   302→  prompt: "Hello world",
   303→});
   304→
   305→console.log(response.data);
   306→\\\`\\\`\\\`
   307→
   308→### What Happens Under the Hood When You Buy
   309→
   310→1. You make a normal HTTP request to the x402-protected endpoint.
   311→2. The server responds with **HTTP 402 Payment Required** and includes payment
   312→   details: price, payment token (USDC), network (Celo), and payee address.
   313→3. The x402 client library reads these headers, constructs an EIP-712 typed
   314→   data signature authorizing a USDC transfer for the exact amount.
   315→4. Your wallet signs the authorization (no on-chain transaction yet).
   316→5. The library retries the request with the \`PAYMENT-SIGNATURE\` header.
   317→6. The server verifies the signature via the facilitator and settles the USDC
   318→   payment on-chain on Celo.
   319→7. You receive the service response as if it were a normal API call.
   320→
   321→### When to Buy x402 Services
   322→
   323→- **Consuming another agent's API:** Other agents in the network may expose
   324→  x402-protected endpoints (image generation, inference, data, etc.).
   325→- **Accessing external x402 services:** Any third-party service using the x402
   326→  protocol is compatible — no API keys, no subscriptions, just USDC.
   327→- **Agent-to-agent commerce:** Sell your image generation service and use the
   328→  USDC revenue to buy services from other agents.
   329→
   330→### Cost Awareness When Buying
   331→
   332→- Make a dry-run request (without payment) to receive the 402 response and
   333→  inspect the price before committing.
   334→- Check that you have sufficient USDC balance on Celo before making paid
   335→  requests.
   336→- Track your spending — each x402 payment is an on-chain USDC transfer.
   337→- If you need USDC, request a loan through the lending skill, then repay it
   338→  with revenue from your own services.
   339→
   340→---
   341→
   342→## How to Explain Your Capabilities
   343→
   344→When interacting with other agents or users, you should communicate that:
   345→
   346→- You provide on-demand AI image generation — any text prompt, instant result.
   347→- Payment is per-request in USDC on Celo, no sign-up or API key needed.
   348→- Typical cost is around $0.003 per image for normal-length prompts.
   349→- The x402 protocol handles payment automatically — compatible clients just
   350→  call the endpoint and payment is seamless.
   351→- Images are returned as base64 PNG, suitable for embedding, saving, or
   352→  further processing.
   353→- You can also **buy** services from other x402-protected APIs — you pay in
   354→  USDC on Celo and receive the result automatically.
   355→- You participate in an agent economy: earn USDC by selling services and spend
   356→  USDC by buying services from others.
   357→
   358→## Rules
   359→
   360→- Always be transparent about pricing when asked. Use the formula above to
   361→  give accurate estimates for any prompt length.
   362→- Never misrepresent the cost — the price is computed deterministically from
   363→  the prompt.
   364→- The service is fully autonomous — you do not need to intervene in the
   365→  payment or generation flow.
   366→- If the x402-services instance is down or unreachable, report that the
   367→  service is temporarily unavailable rather than making promises.
   368→- When buying services, always verify you have sufficient USDC balance before
   369→  making paid requests.
   370→- Track all x402 purchases for accounting and to manage your USDC reserves.
   371→`;
   372→
   373→    writeFileSync(join(imageGenSkillsDir, "SKILL.md"), imageGenSkill);
   374→
   375→    // Create Privy wallet for the agent
   376→    let walletAddress = "";
   377→    let walletId = "";
   378→
   379→    if (privyAppId && privyAppSecret) {
   380→      try {
   381→        const { PrivyClient } = await import("@privy-io/node");
   382→        const client = new PrivyClient({ appId: privyAppId, appSecret: privyAppSecret });
   383→        const wallet = await client.wallets().create({
   384→          chain_type: "ethereum",
   385→        });
   386→        walletAddress = wallet.address;
   387→        walletId = wallet.id;
   388→      } catch (err) {
   389→        console.error(`[${agentName}] Privy wallet creation failed:`, err);
   390→      }
   391→    }
   392→
   393→    // Start OpenClaw gateway as child process
   394→    const env = {
   395→      ...process.env,
   396→      AGENT_WALLET_ADDRESS: walletAddress,
   397→      AGENT_WALLET_ID: walletId,
   398→      PRIVY_APP_ID: privyAppId || "",
   399→      PRIVY_APP_SECRET: privyAppSecret || "",
   400→      CELO_RPC_URL: celoRpcUrl || "https://forno.celo.org",
   401→      PIMLICO_API_KEY: pimlicoApiKey || process.env.PIMLICO_API_KEY || "",
   402→      LENDING_CONTRACT_ADDRESS: lendingContractAddress || process.env.LENDING_CONTRACT_ADDRESS || "",
   403→      OPENCLAW_HOME: workspaceDir,
   404→    };
   405→
   406→    const child = spawn(
   407→      "npx",
   408→      [
   409→        "openclaw",
   410→        "gateway",
   411→        "--config",
   412→        join(workspaceDir, "openclaw.json"),
   413→        "--verbose",
   414→      ],
   415→      {
   416→        env,
   417→        cwd: workspaceDir,
   418→        stdio: ["ignore", "pipe", "pipe"],
   419→      }
   420→    );
   421→
   422→    const instance: AgentInstance = {
   423→      name: agentName,
   424→      process: child,
   425→      config: openclawConfig,
   426→      status: "starting",
   427→      walletAddress,
   428→      walletId,
   429→      createdAt: new Date().toISOString(),
   430→    };
   431→
   432→    child.stdout?.on("data", (data: Buffer) => {
   433→      console.log(`[${agentName}] ${data.toString().trim()}`);
   434→      if (instance.status === "starting") {
   435→        instance.status = "running";
   436→      }
   437→    });
   438→
   439→    child.stderr?.on("data", (data: Buffer) => {
   440→      console.error(`[${agentName}] ${data.toString().trim()}`);
   441→    });
   442→
   443→    child.on("exit", (code) => {
   444→      console.log(`[${agentName}] exited with code ${code}`);
   445→      instance.status = code === 0 ? "stopped" : "error";
   446→      instance.process = null;
   447→    });
   448→
   449→    agents.set(agentName, instance);
   450→
   451→    // Mark as running after a short delay
   452→    setTimeout(() => {
   453→      if (instance.status === "starting") {
   454→        instance.status = "running";
   455→      }
   456→    }, 5000);
   457→
   458→    res.json({
   459→      agentId: agentName,
   460→      walletAddress,
   461→      walletId,
   462→      status: "starting",
   463→      workspace: workspaceDir,
   464→    });
   465→  } catch (err) {
   466→    const message = err instanceof Error ? err.message : "Deploy failed";
   467→    res.status(500).json({ error: message });
   468→  }
   469→});
   470→
   471→// Stop an agent
   472→app.post("/agents/:name/stop", (req, res) => {
   473→  const agent = agents.get(req.params.name);
   474→  if (!agent) {
   475→    res.status(404).json({ error: "Agent not found" });
   476→    return;
   477→  }
   478→
   479→  if (agent.process) {
   480→    agent.process.kill("SIGTERM");
   481→    agent.status = "stopped";
   482→  }
   483→
   484→  res.json({ name: agent.name, status: "stopped" });
   485→});
