     7→/// @notice Minimal interface for the Self Agent Registry (ERC-8004).
     8→interface ISelfAgentRegistry {
     9→    /// @notice Returns the wallet address linked to an agent ID.
    10→    function getAgentWallet(uint256 agentId) external view returns (address);
    11→
    12→    /// @notice Returns true if the agent has an active human-backed proof.
