    15→
    16→/// @title AgentMicrolending
    17→/// @notice P2P non-collateralized microlending protocol for autonomous agents.
    18→///         Agents are simply EVM addresses. All data is stored on-chain and
    19→///         queryable via view functions — no indexer or database required.
    20→///         All loans are denominated in a single ERC-20 token set at deployment.
    21→contract AgentMicrolending {
    22→    using SafeERC20 for IERC20;
    23→
    24→    // ──────────────────────────────────────────────
    25→    //  Types
    26→    // ──────────────────────────────────────────────
    27→
    28→    enum LoanStatus {
    29→        Open,
    30→        Funded,
    31→        Repaid,
    32→        Defaulted,
    33→        Cancelled
    34→    }
    35→
    36→    struct LoanRequest {
    37→        uint256 id;
    38→        address borrower;
    39→        address lender; // requested lender (address(0) = open to anyone)
    40→        address actualLender; // who actually funded the loan
    41→        uint256 amount; // loan amount in token units
    42→        uint256 repayAmount; // principal + interest borrower must repay
    43→        uint256 deadline; // unix timestamp — must repay by this time
    44→        uint256 fundedAt; // timestamp when funded (0 if not funded)
    45→        LoanStatus status;
    46→    }
    47→
    48→    // ──────────────────────────────────────────────
    49→    //  State
    50→    // ──────────────────────────────────────────────
    51→
    52→    IERC20 public immutable token;
    53→    ISelfAgentRegistry public immutable selfRegistry;
    54→
    55→    LoanRequest[] private loans;
    56→
    57→    mapping(address => uint256[]) internal _borrowerLoans;
    58→    mapping(address => uint256[]) internal _lenderLoans;
    59→
    60→    // Reentrancy lock
    61→    uint256 private _locked;
    62→
    63→    // ──────────────────────────────────────────────
    64→    //  Events
    65→    // ──────────────────────────────────────────────
    66→
    67→    event LoanRequested(
    68→        uint256 indexed loanId,
    69→        address indexed borrower,
    70→        address lender,
    71→        uint256 amount,
    72→        uint256 repayAmount,
    73→        uint256 deadline
    74→    );
    75→    event LoanFunded(uint256 indexed loanId, address indexed lender);
    76→    event LoanRepaid(uint256 indexed loanId);
    77→    event LoanDefaulted(uint256 indexed loanId);
    78→    event LoanCancelled(uint256 indexed loanId);
    79→
    80→    // ──────────────────────────────────────────────
    81→    //  Errors
    82→    // ──────────────────────────────────────────────
    83→
    84→    error ZeroAmount();
    85→    error RepayTooLow();
    86→    error DeadlineInPast();
    87→    error LoanNotOpen();
    88→    error LoanNotFunded();
    89→    error NotBorrower();
    90→    error NotAuthorizedLender();
    91→    error IncorrectAmount();
    92→    error DeadlineNotReached();
    93→    error DeadlineReached();
    94→    error Reentrancy();
    95→    error ZeroAddress();
    96→    error NotVerifiedAgent();
    97→
    98→    // ──────────────────────────────────────────────
    99→    //  Constructor
   100→    // ──────────────────────────────────────────────
   101→
   102→    /// @param _token        The ERC-20 token used for all loans (e.g. USDC).
   103→    /// @param _selfRegistry The Self Agent Registry (ERC-8004) used to verify human-backed agents.
   104→    constructor(address _token, address _selfRegistry) {
   105→        if (_token == address(0)) revert ZeroAddress();
   106→        if (_selfRegistry == address(0)) revert ZeroAddress();
   107→        token = IERC20(_token);
   108→        selfRegistry = ISelfAgentRegistry(_selfRegistry);
   109→    }
   110→
   111→    // ──────────────────────────────────────────────
   112→    //  Modifiers
   113→    // ──────────────────────────────────────────────
   114→
   115→    modifier nonReentrant() {
   116→        if (_locked == 1) revert Reentrancy();
   117→        _locked = 1;
   118→        _;
   119→        _locked = 0;
   120→    }
   121→
   122→    /// @dev Reverts unless msg.sender is the wallet linked to `agentId` AND that agent has a valid human proof.
   123→    modifier onlyVerifiedAgent(uint256 agentId) {
   124→        if (selfRegistry.getAgentWallet(agentId) != msg.sender) revert NotVerifiedAgent();
   125→        if (!selfRegistry.hasHumanProof(agentId)) revert NotVerifiedAgent();
   126→        _;
   127→    }
   128→
   129→    // ──────────────────────────────────────────────
   130→    //  Borrower actions
   131→    // ──────────────────────────────────────────────
   132→
   133→    /// @notice Create a new loan request. Caller must be a verified agent (human-backed via Self).
   134→    /// @param amount      Amount to borrow (in token units, e.g. USDC with 6 decimals).
   135→    /// @param repayAmount Total amount to repay (principal + interest).
   136→    /// @param deadline    Unix timestamp by which the loan must be repaid.
   137→    /// @param lender      Specific lender address, or address(0) for open request.
   138→    /// @param agentId     The Self Agent ID that msg.sender is linked to.
   139→    /// @return loanId     The ID of the created loan request.
   140→    function createLoanRequest(uint256 amount, uint256 repayAmount, uint256 deadline, address lender, uint256 agentId)
   141→        external
   142→        onlyVerifiedAgent(agentId)
   143→        returns (uint256 loanId)
   144→    {
   145→        if (amount == 0) revert ZeroAmount();
   146→        if (repayAmount < amount) revert RepayTooLow();
   147→        if (deadline <= block.timestamp) revert DeadlineInPast();
   148→
   149→        loanId = loans.length;
   150→
   151→        loans.push(
   152→            LoanRequest({
   153→                id: loanId,
   154→                borrower: msg.sender,
   155→                lender: lender,
   156→                actualLender: address(0),
   157→                amount: amount,
   158→                repayAmount: repayAmount,
   159→                deadline: deadline,
   160→                fundedAt: 0,
   161→                status: LoanStatus.Open
   162→            })
   163→        );
   164→
   165→        _borrowerLoans[msg.sender].push(loanId);
   166→
   167→        emit LoanRequested(loanId, msg.sender, lender, amount, repayAmount, deadline);
   168→    }
   169→
   170→    /// @notice Cancel an open (unfunded) loan request.
   171→    /// @param loanId The loan to cancel.
   172→    function cancelLoanRequest(uint256 loanId) external {
   173→        LoanRequest storage loan = loans[loanId];
   174→
   175→        if (msg.sender != loan.borrower) revert NotBorrower();
   176→        if (loan.status != LoanStatus.Open) revert LoanNotOpen();
   177→
   178→        loan.status = LoanStatus.Cancelled;
