   182→
   183→    // ──────────────────────────────────────────────
   184→    //  Lender actions
   185→    // ──────────────────────────────────────────────
   186→
   187→    /// @notice Fund an open loan request. Transfers `amount` tokens from the lender to the borrower.
   188→    ///         The lender must have approved this contract for at least `amount` tokens before calling.
   189→    /// @param loanId The loan to fund.
   190→    function fundLoan(uint256 loanId) external nonReentrant {
   191→        LoanRequest storage loan = loans[loanId];
   192→
   193→        if (loan.status != LoanStatus.Open) revert LoanNotOpen();
   194→        if (block.timestamp >= loan.deadline) revert DeadlineReached();
   195→        if (loan.lender != address(0) && msg.sender != loan.lender) revert NotAuthorizedLender();
