   197→        loan.status = LoanStatus.Funded;
   198→        loan.actualLender = msg.sender;
   199→        loan.fundedAt = block.timestamp;
   200→
   201→        _lenderLoans[msg.sender].push(loanId);
   202→
   203→        // Transfer tokens from lender to borrower
   204→        token.safeTransferFrom(msg.sender, loan.borrower, loan.amount);
   205→
   206→        emit LoanFunded(loanId, msg.sender);
   207→    }
   208→
   209→    /// @notice Mark a funded loan as defaulted after the repayment deadline has passed.
   210→    ///         Since loans are non-collateralized, this only updates the status (reputation signal).
   211→    /// @param loanId The loan to mark as defaulted.
   212→    function claimDefaulted(uint256 loanId) external {
   213→        LoanRequest storage loan = loans[loanId];
   214→
   215→        if (loan.status != LoanStatus.Funded) revert LoanNotFunded();
