   217→
   218→        loan.status = LoanStatus.Defaulted;
   219→
   220→        emit LoanDefaulted(loanId);
   221→    }
   222→
   223→    // ──────────────────────────────────────────────
   224→    //  Borrower repayment
   225→    // ──────────────────────────────────────────────
   226→
   227→    /// @notice Repay a funded loan. Transfers `repayAmount` tokens from the borrower to the lender.
   228→    ///         The borrower must have approved this contract for at least `repayAmount` tokens before calling.
   229→    /// @param loanId The loan to repay.
   230→    function repayLoan(uint256 loanId) external nonReentrant {
   231→        LoanRequest storage loan = loans[loanId];
