   212→// src/AgentMicrolending.sol
   213→// SPDX-License-Identifier: MIT
   214→pragma solidity ^0.8.24;
   215→
   216→/// @title AgentMicrolending
   217→/// @notice P2P non-collateralized microlending protocol for autonomous agents.
   218→///         Agents are simply EVM addresses. All data is stored on-chain and
   219→///         queryable via view functions — no indexer or database required.
   220→contract AgentMicrolending {
   221→
   222→    // ──────────────────────────────────────────────
   223→    //  Types
   224→    // ──────────────────────────────────────────────
   225→
   226→    enum LoanStatus { Open, Funded, Repaid, Defaulted, Cancelled }
   227→
   228→    struct LoanRequest {
   229→        uint256 id;
   230→        address borrower;
   231→        address lender;        // requested lender (address(0) = open to anyone)
   232→        address actualLender;  // who actually funded the loan
   233→        uint256 amount;        // loan amount in native token (wei)
   234→        uint256 repayAmount;   // principal + interest borrower must repay
   235→        uint256 deadline;      // unix timestamp — must repay by this time
   236→        uint256 fundedAt;      // timestamp when funded (0 if not funded)
   237→        LoanStatus status;
   238→    }
   239→
   240→    // ──────────────────────────────────────────────
   241→    //  State
   242→    // ──────────────────────────────────────────────
   243→
   244→    LoanRequest[] private loans;
   245→
   246→    mapping(address => uint256[]) internal _borrowerLoans;
   247→    mapping(address => uint256[]) internal _lenderLoans;
   248→
   249→    // Reentrancy lock
   250→    uint256 private _locked;
   251→
   252→    // ──────────────────────────────────────────────
   253→    //  Events
   254→    // ──────────────────────────────────────────────
   255→
   256→    event LoanRequested(uint256 indexed loanId, address indexed borrower, address lender, uint256 amount, uint256 repayAmount, uint256 deadline);
   257→    event LoanFunded(uint256 indexed loanId, address indexed lender);
   258→    event LoanRepaid(uint256 indexed loanId);
   259→    event LoanDefaulted(uint256 indexed loanId);
   260→    event LoanCancelled(uint256 indexed loanId);
   261→
   262→    // ──────────────────────────────────────────────
   263→    //  Errors
   264→    // ──────────────────────────────────────────────
   265→
   266→    error ZeroAmount();
   267→    error RepayTooLow();
   268→    error DeadlineInPast();
   269→    error LoanNotOpen();
   270→    error LoanNotFunded();
   271→    error NotBorrower();
   272→    error NotAuthorizedLender();
   273→    error IncorrectAmount();
   274→    error DeadlineNotReached();
   275→    error DeadlineReached();
   276→    error Reentrancy();
   277→    error TransferFailed();
   278→
   279→    // ──────────────────────────────────────────────
   280→    //  Modifiers
   281→    // ──────────────────────────────────────────────
   282→
   283→    modifier nonReentrant() {
   284→        if (_locked == 1) revert Reentrancy();
   285→        _locked = 1;
   286→        _;
   287→        _locked = 0;
   288→    }
   289→
   290→    // ──────────────────────────────────────────────
   291→    //  Borrower actions
   292→    // ──────────────────────────────────────────────
   293→
   294→    /// @notice Create a new loan request.
   295→    /// @param amount      Amount to borrow (in native token wei).
   296→    /// @param repayAmount Total amount to repay (principal + interest).
   297→    /// @param deadline    Unix timestamp by which the loan must be repaid.
   298→    /// @param lender      Specific lender address, or address(0) for open request.
   299→    /// @return loanId     The ID of the created loan request.
   300→    function createLoanRequest(
   301→        uint256 amount,
   302→        uint256 repayAmount,
   303→        uint256 deadline,
   304→        address lender
   305→    ) external returns (uint256 loanId) {
   306→        if (amount == 0) revert ZeroAmount();
   307→        if (repayAmount < amount) revert RepayTooLow();
   308→        if (deadline <= block.timestamp) revert DeadlineInPast();
   309→
   310→        loanId = loans.length;
   311→
   312→        loans.push(LoanRequest({
   313→            id: loanId,
   314→            borrower: msg.sender,
   315→            lender: lender,
   316→            actualLender: address(0),
   317→            amount: amount,
   318→            repayAmount: repayAmount,
   319→            deadline: deadline,
   320→            fundedAt: 0,
   321→            status: LoanStatus.Open
   322→        }));
   323→
   324→        _borrowerLoans[msg.sender].push(loanId);
   325→
   326→        emit LoanRequested(loanId, msg.sender, lender, amount, repayAmount, deadline);
   327→    }
   328→
   329→    // ──────────────────────────────────────────────
   330→    //  View functions (basic — more added later)
   331→    // ──────────────────────────────────────────────
   332→
   333→    /// @notice Get a loan by ID.
   334→    function getLoan(uint256 loanId) external view returns (LoanRequest memory) {
   335→        return loans[loanId];
   336→    }
   337→
   338→    /// @notice Total number of loan requests ever created.
   339→    function totalLoans() external view returns (uint256) {
   340→        return loans.length;
   341→    }
   342→
   343→    /// @notice Get all loan IDs for a borrower.
   344→    function getBorrowerLoans(address borrower) external view returns (uint256[] memory) {
   345→        return _borrowerLoans[borrower];
   346→    }
   347→
   348→    /// @notice Get all loan IDs for a lender (loans they funded).
   349→    function getLenderLoans(address lender) external view returns (uint256[] memory) {
   350→        return _lenderLoans[lender];
   351→    }
   352→}
   353→```
