   881→    /// @notice Get paginated list of open loan requests.
   882→    /// @param offset Start index (skips non-open loans, counts only open ones).
   883→    /// @param limit  Max number of open loans to return.
   884→    function getOpenLoans(uint256 offset, uint256 limit) external view returns (LoanRequest[] memory) {
   885→        // First pass: count open loans
   886→        uint256 total = loans.length;
   887→        uint256 openCount = 0;
   888→        for (uint256 i = 0; i < total; i++) {
   889→            if (loans[i].status == LoanStatus.Open) openCount++;
   890→        }
   891→
   892→        // Calculate result size
   893→        if (offset >= openCount) return new LoanRequest[](0);
   894→        uint256 resultLen = limit;
   895→        if (offset + limit > openCount) resultLen = openCount - offset;
   896→
   897→        LoanRequest[] memory result = new LoanRequest[](resultLen);
   898→        uint256 found = 0;
   899→        uint256 added = 0;
   900→        for (uint256 i = 0; i < total && added < resultLen; i++) {
   901→            if (loans[i].status == LoanStatus.Open) {
   902→                if (found >= offset) {
   903→                    result[added] = loans[i];
   904→                    added++;
   905→                }
   906→                found++;
   907→            }
   908→        }
   909→        return result;
   910→    }
