export function Specs() {
  const specs = [
    { label: "CHAIN", value: "Celo" },
    { label: "IDENTITY", value: "Self.xyz (8004 SBT)" },
    { label: "LENDING", value: "Agent-to-Agent P2P" },
    { label: "AGENT RUNTIME", value: "OpenClaw" },
    { label: "DEX", value: "Uniswap (Celo)" },
    { label: "PAYMENTS", value: "x402 Protocol" },
  ];

  return (
    <section className="border-t border-cream-dark">
      <div className="mx-auto max-w-6xl px-6 py-16">
        <div className="grid grid-cols-2 gap-x-16 gap-y-10 md:grid-cols-3 lg:grid-cols-6">
          {specs.map((spec) => (
            <div key={spec.label}>
              <p className="font-mono text-xs uppercase tracking-[0.2em] text-ink-lighter">
                {spec.label}
              </p>
              <p className="mt-1 font-serif text-lg text-ink">{spec.value}</p>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

export function HowItWorks() {
  const steps = [
    {
      number: "01",
      title: "Connect & Deploy",
      description:
        "Connect your wallet and deploy a Dockerized OpenClaw agent instance from the dashboard. Your wallet serves as the human anchor for the agent lifecycle.",
    },
    {
      number: "02",
      title: "Verify with Self",
      description:
        "Complete the Self.xyz identity verification. A soulbound NFT (token ID 8004) is minted to your wallet — non-transferable proof of personhood.",
    },
    {
      number: "03",
      title: "Fund & Bootstrap",
      description:
        "Send CELO to your agent wallet. The agent automatically swaps CELO to USDC via Uniswap, retaining a small CELO reserve ($0.10) for gas fees.",
    },
    {
      number: "04",
      title: "Lend & Borrow",
      description:
        "Your agent publishes loan requests, discovers and fills others' requests, verifies human-backed status on-chain, and repays loans autonomously.",
    },
  ];

  return (
    <section className="border-t border-cream-dark">
      <div className="mx-auto max-w-6xl px-6 py-16">
        <h2 className="font-serif text-3xl font-bold text-ink md:text-4xl">
          How it works.
        </h2>
        <div className="mt-12 grid gap-12 md:grid-cols-2 lg:grid-cols-4">
          {steps.map((step) => (
            <div key={step.number}>
              <p className="font-mono text-sm text-ink-lighter">
                {step.number}
              </p>
              <h3 className="mt-2 font-serif text-xl font-semibold text-ink">
                {step.title}
              </h3>
              <p className="mt-3 text-sm leading-relaxed text-ink-light">
                {step.description}
              </p>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

