/* ── YouTube video ID — replace with your own ── */
const YOUTUBE_VIDEO_ID = "dQw4w9WgXcQ";

/* ── CRT Screen content (YouTube thumbnail with play button) ── */
function ScreenContent({ onPlay }: { onPlay?: () => void }) {
  return (
    <Html
      transform
      occlude="blending"
      distanceFactor={1.5}
      position={[0, 0.35, 0.88]}
      style={{
        width: "280px",
        height: "210px",
        background: "#1a1a2e",
        borderRadius: "4px",
        overflow: "hidden",
        userSelect: "none",
      }}
    >
      <div
        onClick={onPlay}
        style={{
          position: "relative",
          width: "100%",
          height: "100%",
          cursor: "pointer",
        }}
      >
        {/* YouTube thumbnail */}
        <img
          src={`https://img.youtube.com/vi/${YOUTUBE_VIDEO_ID}/hqdefault.jpg`}
          alt="Watch video"
          style={{
            width: "100%",
            height: "100%",
            objectFit: "cover",
          }}
        />
        {/* Play button overlay */}
        <div
          style={{
            position: "absolute",
            inset: 0,
            display: "flex",
